138	    /// <summary>
139	    /// Revokes the original refresh token and any replacement issued while logout and refresh overlap.
140	    /// </summary>
141	    [Fact]
142	    public async Task Logout_ConcurrentWithRefresh_RevokesOriginalAndAnyReplacement()
143	    {
144	        // Arrange
145	        using var registration = await RegisterAsync();
146	        var originalCookie = GetRefreshCookieValue(registration);
147	        var start = new TaskCompletionSource(TaskCreationOptions.RunContinuationsAsynchronously);
148	
149	        // Act
150	        var logoutTask = StartWhenReleasedAsync(
151	            start.Task,
152	            () => SendWithRefreshCookieAsync(HttpMethod.Post, "/api/auth/logout", originalCookie));
153	        var refreshTask = StartWhenReleasedAsync(start.Task, () => RefreshAsync(originalCookie));
154	        start.SetResult();
155	
156	        using var logout = await logoutTask;
157	        using var refresh = await refreshTask;
158	        var issuedCookies = new List<string> { originalCookie };
159	        if (refresh.StatusCode == HttpStatusCode.OK)
160	        {
161	            issuedCookies.Add(GetRefreshCookieValue(refresh));
162	        }
163	
164	        var refreshAttempts = await Task.WhenAll(issuedCookies.Select(RefreshAsync));
165	        using var originalAttempt = refreshAttempts[0];
166	        if (refreshAttempts.Length > 1)
167	        {
168	            using var replacementAttempt = refreshAttempts[1];
169	            Assert.Equal(HttpStatusCode.Unauthorized, replacementAttempt.StatusCode);
170	        }
171	
172	        // Assert
173	        Assert.Equal(HttpStatusCode.NoContent, logout.StatusCode);
174	        Assert.True(
175	            refresh.StatusCode is HttpStatusCode.OK or HttpStatusCode.Unauthorized,
176	            $"Expected refresh to succeed or be unauthorized, but received {refresh.StatusCode}.");
177	        Assert.Equal(HttpStatusCode.Unauthorized, originalAttempt.StatusCode);
178	    }
179	
180	    private static async Task<T> StartWhenReleasedAsync<T>(Task start, Func<Task<T>> operation)
181	    {
182	        await start;
183	        return await operation();
184	    }
185	
186	    private async Task<HttpResponseMessage> RegisterAsync()
187	    {
188	        var suffix = Guid.NewGuid().ToString("N");
189	        return await _client.PostAsJsonAsync(
190	            "/api/auth/register",
191	            new RegisterUserCommand($"User {suffix}", $"user-{suffix}@example.test", "Password!12345"));
192	    }
193	
194	    private async Task<HttpResponseMessage> RefreshAsync(string refreshCookie) =>
195	        await SendWithRefreshCookieAsync(HttpMethod.Post, "/api/auth/refresh", refreshCookie);
196	
197	    private async Task<HttpResponseMessage> SendWithRefreshCookieAsync(
198	        HttpMethod method,
199	        string path,
200	        string refreshCookie)
201	    {
202	        using var request = new HttpRequestMessage(method, path);
203	        request.Headers.Add("Cookie", $"{RefreshCookieName}={refreshCookie}");
204	        return await _client.SendAsync(request);
205	    }
206	
207	    private static async Task<AuthenticationResponse> ReadSessionAsync(HttpResponseMessage response)
208	    {
209	        var session = await response.Content.ReadFromJsonAsync<AuthenticationResponse>(JsonOptions);
210	        return Assert.IsType<AuthenticationResponse>(session);
211	    }
212	
213	    private static string GetRefreshCookieHeader(HttpResponseMessage response) =>
214	        Assert.Single(response.Headers.GetValues("Set-Cookie"));
215	
216	    private static string GetRefreshCookieValue(HttpResponseMessage response)
217	    {
218	        var header = GetRefreshCookieHeader(response);
219	        var cookie = header.Split(';', 2)[0].Split('=', 2);
220	        Assert.Equal(RefreshCookieName, cookie[0]);
221	        return Uri.UnescapeDataString(cookie[1]);
222	    }
223	}
