  1	export const getSafeReturnPath = (value: unknown) => {
  2	  if (
  3	    typeof value !== "string" ||
  4	    !value.startsWith("/") ||
  5	    value.startsWith("//")
  6	  )
  7	    return "/dashboard"
  8	
  9	  try {
 10	    const url = new URL(value, window.location.origin)
 11	    return url.origin === window.location.origin
 12	      ? `${url.pathname}${url.search}${url.hash}`
 13	      : "/dashboard"
 14	  } catch {
 15	    return "/dashboard"
 16	  }
 17	}

