  1	using InventoryFlow.Application.Features.Authentication;
  2	using InventoryFlow.Domain.Entities;
  3	using InventoryFlow.Infrastructure.Identity;
  4	using InventoryFlow.Infrastructure.Persistence;
  5	using Microsoft.AspNetCore.Identity;
  6	using Microsoft.EntityFrameworkCore;
  7	using Microsoft.Extensions.Options;
  8	using System.Data;
  9	
 10	namespace InventoryFlow.Infrastructure.Authentication;
 11	
 12	/// <summary>Implements identity, session issuance, and refresh rotation.</summary>
 13	public sealed class IdentityAuthenticationService(
 14	    UserManager<ApplicationUser> userManager,
 15	    SignInManager<ApplicationUser> signInManager,
 16	    ApplicationDbContext dbContext,
 17	    JwtAccessTokenIssuer accessTokenIssuer,
 18	    RefreshTokenGenerator refreshTokenGenerator,
 19	    IOptions<JwtOptions> options,
 20	    TimeProvider timeProvider) : IAuthenticationService
 21	{
 22	    private readonly JwtOptions _options = options.Value;
 23	
 24	    /// <inheritdoc />
 25	    public async Task<AuthenticationSession> RegisterAsync(RegisterUserCommand command, CancellationToken cancellationToken)
 26	    {
 27	        var user = new ApplicationUser { Id = Guid.NewGuid(), UserName = command.Email.Trim(), Email = command.Email.Trim(), DisplayName = command.DisplayName.Trim() };
 28	        var result = await userManager.CreateAsync(user, command.Password);
 29	        if (!result.Succeeded) throw new AuthenticationException();
 30	        return await IssueSessionAsync(user, Guid.NewGuid(), cancellationToken);
 31	    }
 32	
 33	    /// <inheritdoc />
 34	    public async Task<AuthenticationSession?> LoginAsync(LoginUserCommand command, CancellationToken cancellationToken)
 35	    {
 36	        var user = await userManager.FindByEmailAsync(command.Email.Trim());
 37	        if (user is null) return null;
 38	        var result = await signInManager.CheckPasswordSignInAsync(user, command.Password, lockoutOnFailure: true);
 39	        return result.Succeeded ? await IssueSessionAsync(user, Guid.NewGuid(), cancellationToken) : null;
 40	    }
 41	
 42	    /// <inheritdoc />
 43	    public async Task<AuthenticationSession?> RefreshAsync(string refreshToken, CancellationToken cancellationToken)
 44	    {
 45	        var now = timeProvider.GetUtcNow();
 46	        var hash = refreshTokenGenerator.Hash(refreshToken);
 47	        var strategy = dbContext.Database.CreateExecutionStrategy();
 48	
 49	        return await strategy.ExecuteAsync(async () =>
 50	        {
 51	            await using var transaction = await dbContext.Database.BeginTransactionAsync(
 52	                IsolationLevel.Serializable,
 53	                cancellationToken);
 54	            var token = await dbContext.RefreshTokens.SingleOrDefaultAsync(
 55	                item => item.TokenHash == hash,
 56	                cancellationToken);
 57	
 58	            if (token is null)
 59	            {
 60	                await transaction.CommitAsync(cancellationToken);
 61	                return null;
 62	            }
 63	
 64	            if (!token.IsActive(now))
 65	            {
 66	                await RevokeFamilyAsync(token.FamilyId, now, cancellationToken);
 67	                await dbContext.SaveChangesAsync(cancellationToken);
 68	                await transaction.CommitAsync(cancellationToken);
 69	                return null;
 70	            }
 71	
 72	            token.Revoke(now);
 73	            var user = await userManager.FindByIdAsync(token.UserId.ToString());
 74	            if (user is null)
 75	            {
 76	                await dbContext.SaveChangesAsync(cancellationToken);
 77	                await transaction.CommitAsync(cancellationToken);
 78	                return null;
 79	            }
 80	
 81	            var session = CreateSession(user, token.FamilyId, now);
 82	            dbContext.RefreshTokens.Add(session.Token);
 83	            await dbContext.SaveChangesAsync(cancellationToken);
 84	            await transaction.CommitAsync(cancellationToken);
 85	            return session.Session;
 86	        });
 87	    }
 88	
 89	    /// <inheritdoc />
 90	    public async Task LogoutAsync(string? refreshToken, CancellationToken cancellationToken)
 91	    {
 92	        if (string.IsNullOrWhiteSpace(refreshToken)) return;
 93	
 94	        var hash = refreshTokenGenerator.Hash(refreshToken);
 95	        var now = timeProvider.GetUtcNow();
 96	        var strategy = dbContext.Database.CreateExecutionStrategy();
 97	
 98	        await strategy.ExecuteAsync(async () =>
 99	        {
100	            await using var transaction = await dbContext.Database.BeginTransactionAsync(
101	                IsolationLevel.Serializable,
102	                cancellationToken);
103	            var token = await dbContext.RefreshTokens.SingleOrDefaultAsync(
104	                item => item.TokenHash == hash,
105	                cancellationToken);
106	
107	            if (token is not null)
108	            {
109	                await RevokeFamilyAsync(token.FamilyId, now, cancellationToken);
110	                await dbContext.SaveChangesAsync(cancellationToken);
111	            }
112	
113	            await transaction.CommitAsync(cancellationToken);
114	        });
115	    }
116	
117	    /// <inheritdoc />
118	    public async Task<AuthenticatedUser?> GetUserAsync(Guid userId, CancellationToken cancellationToken)
119	    {
120	        var user = await userManager.FindByIdAsync(userId.ToString());
121	        return user is null ? null : ToUser(user);
122	    }
123	
124	    private async Task<AuthenticationSession> IssueSessionAsync(ApplicationUser user, Guid familyId, CancellationToken cancellationToken)
125	    {
126	        var created = CreateSession(user, familyId, timeProvider.GetUtcNow());
127	        dbContext.RefreshTokens.Add(created.Token);
128	        await dbContext.SaveChangesAsync(cancellationToken);
129	        return created.Session;
130	    }
131	
132	    private (AuthenticationSession Session, RefreshToken Token) CreateSession(ApplicationUser user, Guid familyId, DateTimeOffset now)
133	    {
134	        var refreshValue = refreshTokenGenerator.Create();
135	        var token = new RefreshToken(Guid.NewGuid(), user.Id, familyId, refreshTokenGenerator.Hash(refreshValue), now.AddDays(_options.RefreshTokenLifetimeDays));
136	        var access = accessTokenIssuer.Issue(ToUser(user));
137	        return (new AuthenticationSession(new AuthenticationResponse(access.Token, access.ExpiresAtUtc, ToUser(user)), refreshValue), token);
138	    }
139	
140	    private async Task RevokeFamilyAsync(Guid familyId, DateTimeOffset now, CancellationToken cancellationToken)
141	    {
142	        var activeTokens = await dbContext.RefreshTokens.Where(item => item.FamilyId == familyId && item.RevokedAtUtc == null && item.ExpiresAtUtc > now).ToListAsync(cancellationToken);
143	        foreach (var token in activeTokens) token.Revoke(now);
144	    }
145	
146	    private static AuthenticatedUser ToUser(ApplicationUser user) => new(user.Id, user.Email ?? string.Empty, user.DisplayName);
147	}
